// vmISOFilename is the per-VM cloud-init ISO name. Stable across
// reboots (keyed off vmid, not hostname) so the storage volid stays
// valid for the VM's lifetime; cleaned up when the VM is destroyed.
func vmISOFilename(vmid int) string {
	return fmt.Sprintf("nimbus-vm-%d.iso", vmid)
}
